import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  Spacer,
  Badge,
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface Props {
  initialProfile?: ProfileData;
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({ initialProfile, avatarOptions, roleOptions, onComplete }: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  const [name, setName] = useState(initialProfile?.name ?? '');
  const [email, setEmail] = useState(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar ?? '');
  const [role, setRole] = useState(initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme ?? 'light');

  const [emailTouched, setEmailTouched] = useState(false);
  const [nameTouched, setNameTouched] = useState(false);
  const [animDirection, setAnimDirection] = useState<'forward' | 'backward'>('forward');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = nameTouched && !name.trim() ? 'Name is required' : '';
  const emailError = emailTouched ? (!email.trim() ? 'Email is required' : !emailRegex.test(email) ? 'Invalid email format' : '') : '';

  const step1Valid = name.trim() !== '' && email.trim() !== '' && emailRegex.test(email) && avatar !== '';
  const step2Valid = role !== '';
  const canNext = currentStep === 0 ? step1Valid : currentStep === 1 ? step2Valid : true;

  const goNext = () => {
    if (currentStep < steps.length - 1 && canNext) {
      setAnimDirection('forward');
      setCurrentStep((s) => s + 1);
    }
  };

  const goBack = () => {
    if (currentStep > 0) {
      setAnimDirection('backward');
      setCurrentStep((s) => s - 1);
    }
  };

  const handleComplete = () => {
    if (onComplete) {
      onComplete({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
    }
  };

  const roleSelectOptions = useMemo(() => roleOptions.map((r) => ({ value: r, label: r })), [roleOptions]);
  const themeSelectOptions = [{ value: 'light', label: '☀️ Light' }, { value: 'dark', label: '🌙 Dark' }];

  // Progress bar width derived from fixed step index — no user data interpolated
  const progressWidths: Record<number, string> = { 0: '0%', 1: '50%', 2: '100%' };
  const progressWidth = progressWidths[currentStep] ?? '0%';

  // Step circle aria-labels built without template literals
  const buildStepAriaLabel = (label: string, idx: number, completed: boolean, active: boolean): string => {
    const num = String(idx + 1);
    if (completed) return 'Step ' + num + ': ' + label + ' (completed)';
    if (active) return 'Step ' + num + ': ' + label + ' (current)';
    return 'Step ' + num + ': ' + label;
  };

  const nextStepAriaLabel = 'Proceed to step ' + String(currentStep + 2);

  const stepIndicator = (
    <Stack direction="vertical" gap={16}>
