                aria-label="Avatar option"
                tabIndex={0}
                onClick={() => setAvatar(emojiOption)}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setAvatar(emojiOption); } }}
                style={{
                  width: 56, height: 56,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 28, cursor: 'pointer',
                  transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                  border: isSelected ? '3px solid var(--ggui-color-primary, #0ea5e9)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                  background: isSelected ? 'var(--ggui-color-primaryContainer, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  boxShadow: isSelected ? '0 0 0 3px var(--ggui-color-primaryContainer, #e0f2fe)' : 'none',
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
