      <Stack direction="vertical" gap={4}>
        <Text variant="h3">Preferences</Text>
        <Text variant="body">Customize your experience to fit your workflow.</Text>
      </Stack>
      <Select label="Role" value={role} onChange={(v: string) => setRole(v)} options={roleSelectOptions} placeholder="Select your role" required />
      <Checkbox label="Email Notifications" checked={emailNotifications} onChange={(v: boolean) => setEmailNotifications(v)} description="Receive email updates about activity and announcements" />
      <Select label="Theme Preference" value={theme} onChange={(v: string) => setTheme(v)} options={themeSelectOptions} />
    </Stack>
  );

  const step3 = (
    <Stack direction="vertical" gap={20}>
