  const stepContent = [step1, step2, step3];

  const slideInAnim = 'ggui-slide-in-up 250ms cubic-bezier(0.4, 0, 0.2, 1) both';
  const fadeInAnim = 'ggui-fade-in 200ms ease both';

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={32} shadow="md" border>
        <Stack direction="vertical" gap={28}>
          <Text variant="h2" align="center">Welcome! Let's set you up</Text>
          <div role="list" aria-label="Onboarding steps">{stepIndicator}</div>
