import React from 'react';
import { Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * A helper to resolve an emoji for common weather conditions if no icon is provided
 */
const getWeatherEmoji = (condition: string = ''): string => {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('snow') || c.includes('ice')) return '❄️';
  if (c.includes('mist') || c.includes('fog')) return '🌫️';
  return '🌡️';
};

/**
 * WeatherCard Component
 * Displays current weather details and a 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const currentEmoji = getWeatherEmoji(condition);

  return (
    <Card 
      shadow="md" 
      padding="var(--ggui-spacing-6, 24px)"
      style={{ 
        maxWidth: 480, 
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)'
      }}
    >
      <Stack gap={24}>
        {/* Header Section: City & Description */}
        <Stack gap={4}>
          <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Section */}
        <Row align="center" justify="between">
          <Stack direction="horizontal" align="start" gap={4}>
            <Text 
              style={{ 
                fontSize: 'var(--ggui-font-size-4xl, 36px)', 
                lineHeight: 1 
              }} 
              weight="bold"
            >
              {Math.round(temperature)}
            </Text>
            <Text 
              variant="h3" 
              weight="medium" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ marginTop: 4 }}
            >
              {'°' + unit}
            </Text>
          </Stack>

          <Text style={{ fontSize: 64 }}>
            {currentEmoji}
          </Text>
        </Row>

        {/* Details Section: Humidity & Wind */}
        <Row gap={24}>
          <Stack gap={2}>
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              HUMIDITY
            </Text>
            <Text variant="body" weight="semibold">
              {humidity + '%'}
            </Text>
          </Stack>
          <Stack gap={2}>
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              WIND
            </Text>
            <Text variant="body" weight="semibold">
              {windSpeed + ' ' + (unit === 'C' ? 'km/h' : 'mph')}
            </Text>
          </Stack>
        </Row>

        <Divider margin={0} />

        {/* 5-Day Forecast Strip */}
        <Row justify="between" wrap>
          {forecast.map((item, index) => (
            <Stack 
              key={item.day || index} 
              align="center" 
              gap={8}
              style={{ minWidth: 60 }}
            >
              <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day ? item.day.toUpperCase() : '---'}
              </Text>

              <Text style={{ fontSize: 24 }}>
                {item.icon || getWeatherEmoji(condition)}
              </Text>

              <Stack gap={0} align="center">
                <Text variant="bodySmall" weight="bold">
                  {item.high !== undefined ? item.high + '°' : '--°'}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low !== undefined ? item.low + '°' : '--°'}
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface PeriodicElement {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<PeriodicElement>;
}

/**
 * Maps element categories to design system color tokens
 */
const getCategoryColor = (category?: string): string => {
  switch (category) {
    case 'alkali-metal': return 'var(--ggui-color-primary-low, #e0f2fe)';
    case 'alkaline-earth': return 'var(--ggui-color-primary-medium, #bae6fd)';
    case 'transition-metal': return 'var(--ggui-color-secondary-low, #f5f3ff)';
    case 'post-transition-metal': return 'var(--ggui-color-info-low, #e0f2fe)';
    case 'metalloid': return 'var(--ggui-color-warning-low, #fef3c7)';
    case 'nonmetal': return 'var(--ggui-color-error-low, #fee2e2)';
    case 'halogen': return 'var(--ggui-color-success-low, #dcfce7)';
    case 'noble-gas': return 'var(--ggui-color-primary-high, #7dd3fc)';
    case 'lanthanide': return 'var(--ggui-color-secondary-high, #c4b5fd)';
    case 'actinide': return 'var(--ggui-color-info-high, #7dd3fc)';
    default: return 'var(--ggui-color-surface-variant, #f3f4f6)';
  }
};

const CATEGORIES = [
  { label: 'Alkali Metal', value: 'alkali-metal' },
  { label: 'Alkaline Earth', value: 'alkaline-earth' },
  { label: 'Transition Metal', value: 'transition-metal' },
  { label: 'Post-transition Metal', value: 'post-transition-metal' },
  { label: 'Metalloid', value: 'metalloid' },
  { label: 'Nonmetal', value: 'nonmetal' },
  { label: 'Halogen', value: 'halogen' },
  { label: 'Noble Gas', value: 'noble-gas' },
  { label: 'Lanthanide', value: 'lanthanide' },
  { label: 'Actinide', value: 'actinide' },
];

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<PeriodicElement | null>(null);

  const isFiltered = (el: PeriodicElement): boolean => {
    if (!searchTerm) return true;
    const lowerSearch = searchTerm.toLowerCase();
    const nameMatch = el.name?.toLowerCase().includes(lowerSearch) ?? false;
    const symbolMatch = el.symbol?.toLowerCase().includes(lowerSearch) ?? false;
    return nameMatch || symbolMatch;
  };

  return (
    <Stack direction="column" gap="xl" style={{ width: '100%', maxWidth: '1200px', margin: '0 auto', padding: 'var(--ggui-space-m, 16px)' }}>
      {/* Header & Filter */}
      <Stack direction="row" align="center" justify="space-between" wrap="wrap" gap="m">
        <Stack direction="column" gap="xs">
          <Text variant="headline-medium">Periodic Table</Text>
          <Text variant="body-small" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>
            Interactive element reference
          </Text>
        </Stack>
        <div style={{ width: '100%', maxWidth: 'var(--ggui-space-xxxxxl, 300px)' }}>
          <Text as="label" htmlFor="search" variant="label-medium">Filter</Text>
          <Input id="search" label="Filter" value={searchTerm} onChange={setSearchTerm} placeholder="Search elements..." />
        </div>
      </Stack>

      {/* Legend */}
      <Stack direction="row" gap="s" wrap="wrap" style={{ padding: 'var(--ggui-space-s, 8px)', background: 'var(--ggui-color-surface-variant, #f9fafb)', borderRadius: 'var(--ggui-radius-m, 8px)' }}>
        {CATEGORIES.map(cat => (
          <Stack key={cat.value} direction="row" align="center" gap="xs">
            <div style={{ width: 'var(--ggui-space-s, 12px)', height: 'var(--ggui-space-s, 12px)', borderRadius: 'var(--ggui-radius-xs, 2px)', backgroundColor: getCategoryColor(cat.value) }} />
            <Text variant="label-small">{cat.label}</Text>
          </Stack>
        ))}
      </Stack>

      {/* Grid Container */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(18, 1fr)', 
        gridAutoRows: 'minmax(var(--ggui-space-xxxxl, 64px), auto)',
        gap: 'var(--ggui-space-xxs, 4px)',
        overflowX: 'auto',
        padding: 'var(--ggui-space-xxs, 4px)'
      }}>
        {elements.map((el) => {
          const isActive = isFiltered(el);
          const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
          const bgColor = getCategoryColor(el.category);

          return (
            <div
              key={el.atomicNumber}
              onClick={() => setSelectedElement(el)}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') setSelectedElement(el); }}
              aria-label={el.name || el.symbol}
              style={{
                gridColumn: el.col,
                gridRow: el.row,
                cursor: 'pointer',
                transition: 'transform 0.2s, opacity 0.2s',
                opacity: isActive ? 1 : 0.2,
                transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                zIndex: isSelected ? 10 : 1,
                outline: 'none',
                height: '100%'
              }}
            >
              <Card 
                variant={isSelected ? 'outline' : 'filled'}
                style={{ 
                  height: '100%', 
                  padding: 'var(--ggui-space-xxs, 4px)', 
                  backgroundColor: bgColor,
                  border: isSelected ? 'var(--ggui-border-width-m, 2px) solid var(--ggui-color-primary, #3b82f6)' : 'var(--ggui-border-width-s, 1px) solid var(--ggui-color-outline, #e5e7eb)',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  position: 'relative',
                  minWidth: 'var(--ggui-space-xxxxl, 48px)',
                  boxSizing: 'border-box'
                }}
              >
                <div style={{ position: 'absolute', top: 'var(--ggui-space-xxxs, 2px)', left: 'var(--ggui-space-xxs, 4px)' }}>
                  <Text variant="label-small" style={{ fontSize: 'var(--ggui-font-size-xs, 10px)' }}>{el.atomicNumber}</Text>
                </div>
                <div style={{ textAlign: 'center' }}>
                  <Text variant="title-medium" style={{ fontWeight: 'bold' }}>{el.symbol}</Text>
                </div>
                <div style={{ width: '100%', overflow: 'hidden' }}>
                   <Text variant="label-small" style={{ fontSize: 'var(--ggui-font-size-xxs, 8px)', textAlign: 'center', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>
                    {el.name}
                  </Text>
                </div>
              </Card>
            </div>
          );
        })}
      </div>

      {/* Detail Panel */}
      {selectedElement && (
        <Card variant="outline" style={{ overflow: 'hidden' }}>
          <Stack direction="row" gap="none" style={{ height: '100%' }}>
            <div style={{ width: 'var(--ggui-space-s, 8px)', backgroundColor: getCategoryColor(selectedElement.category) }} />
            <Stack direction="column" gap="m" style={{ flex: 1, padding: 'var(--ggui-space-l, 24px)' }}>
              <Stack direction="row" justify="space-between" align="start">
                <Stack direction="row" align="baseline" gap="s" wrap="wrap">
                  <Text variant="headline-large">{selectedElement.name}</Text>
                  <Text variant="title-large" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>({selectedElement.symbol})</Text>
                </Stack>
                <Button variant="ghost" onClick={() => setSelectedElement(null)}>Close</Button>
              </Stack>

              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(var(--ggui-space-xxxxxl, 192px), 1fr))', gap: 'var(--ggui-space-m, 16px)' }}>
                <Stack direction="column" gap="none">
                  <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>Atomic Number</Text>
                  <Text variant="body-large">{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack direction="column" gap="none">
                  <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>Atomic Weight</Text>
                  <Text variant="body-large">{selectedElement.atomicWeight} u</Text>
                </Stack>
                <Stack direction="column" gap="none">
                  <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>Category</Text>
                  <Text variant="body-large" style={{ textTransform: 'capitalize' }}>
                    {selectedElement.category ? selectedElement.category.split('-').join(' ') : ''}
                  </Text>
                </Stack>
                <Stack direction="column" gap="none">
                  <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>Electron Configuration</Text>
                  <Text variant="body-large">{selectedElement.electronConfiguration}</Text>
                </Stack>
              </div>
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

