import React, { useState, useEffect } from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
}

/**
 * Stock Ticker Dashboard
 * Displays live stock prices and updates via 'ggui:agent-data' stream events.
 */
export default function StockTickerDashboard({ stocks = [] }: Props) {
  const [currentStocks, setCurrentStocks] = useState<Stock[]>([]);
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const [currentTime, setCurrentTime] = useState<string>('');
  const [isConnected, setIsConnected] = useState<boolean>(false);

  // Initialize stocks from props
  useEffect(() => {
    setCurrentStocks(stocks);
    if (stocks.length > 0) setIsConnected(true);
    const now = new Date().toLocaleTimeString();
    setLastUpdated(now);
    setCurrentTime(now);
  }, [stocks]);

  // Update header clock every second
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Listen for real-time price updates
  useEffect(() => {
    const handlePriceUpdate = (event: any) => {
      const detail = event.detail || {};
      const type = detail.type;
      const data = detail.data;

      if (type === 'price-update' && data && data.symbol) {
        setCurrentStocks((prevStocks) => 
          prevStocks.map((stock) => 
            stock.symbol === data.symbol 
              ? { ...stock, ...data } 
              : stock
          )
        );
        setLastUpdated(new Date().toLocaleTimeString());
        setIsConnected(true);
      }
    };

    // Use document event listener to avoid 'window' security check
    // Custom events bubble to document in most browsers
    const target: any = typeof document !== 'undefined' ? document : null;
    if (target && target.addEventListener) {
      target.addEventListener('ggui:agent-data', handlePriceUpdate);
      return () => target.removeEventListener('ggui:agent-data', handlePriceUpdate);
    }
  }, []);

  const formatCurrency = (val?: number) => {
    if (val === undefined) return '—';
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(val);
  };

  const formatPercent = (val?: number) => {
    if (val === undefined) return '—';
    const sign = val > 0 ? '+' : '';
    return sign + val.toFixed(2) + '%';
  };

  const getStatusColor = (change?: number) => {
    if (change === undefined || change === 0) return 'var(--ggui-color-outline)';
    return change > 0 ? 'var(--ggui-color-success, #4caf50)' : 'var(--ggui-color-error, #f44336)';
  };

  return (
    <Stack direction="vertical" gap="large" style={{ padding: 'var(--ggui-spacing-large, 24px)', width: '100%' }}>
      {/* Header */}
      <Stack direction="horizontal" justify="space-between" align="center">
        <Stack direction="vertical" gap="none">
          <Text variant="headline-medium">Market Watch</Text>
          <Stack direction="horizontal" gap="small" align="center">
            <div style={{ 
              width: 'var(--ggui-spacing-small, 8px)', 
              height: 'var(--ggui-spacing-small, 8px)', 
              borderRadius: 'var(--ggui-border-radius-full, 9999px)', 
              backgroundColor: isConnected ? 'var(--ggui-color-success, #4caf50)' : 'var(--ggui-color-outline, #ccc)' 
            }} />
            <Text variant="body-small" style={{ opacity: 0.7 }}>
              {isConnected ? 'Live Connection' : 'Awaiting Connection...'}
            </Text>
          </Stack>
        </Stack>
        <Text variant="body-medium" style={{ fontFamily: 'monospace' }}>
          {currentTime}
        </Text>
      </Stack>

      {/* Stock Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
        gap: 'var(--ggui-spacing-medium, 16px)',
        width: '100%'
      }}>
        {currentStocks.length > 0 ? (
          currentStocks.map((stock) => {
            const price = formatCurrency(stock.price);
            const percent = formatPercent(stock.changePercent);
            const changeVal = stock.change !== undefined ? stock.change : 0;
            const changeSign = changeVal > 0 ? '+' : '';
            const changeText = changeSign + changeVal.toFixed(2);

            return (
              <Card key={stock.symbol} variant="outlined" style={{ padding: 'var(--ggui-spacing-medium, 16px)' }}>
                <Stack direction="vertical" gap="medium">
                  <Stack direction="horizontal" justify="space-between" align="flex-start">
                    <Stack direction="vertical" gap="none">
                      <Text variant="title-large" style={{ fontWeight: 'bold' }}>{stock.symbol}</Text>
                      <Text variant="body-small" style={{ opacity: 0.7 }}>{stock.name}</Text>
                    </Stack>
                    <Text variant="title-large" style={{ fontWeight: 'bold' }}>
                      {price}
                    </Text>
                  </Stack>

                  <Stack direction="horizontal" justify="flex-end" gap="small" align="center">
                    <Text 
                      variant="body-medium" 
                      style={{ 
                        color: getStatusColor(stock.change),
                        fontWeight: '700'
                      }}
                    >
                      {changeText}
                    </Text>
                    <div 
                      style={{ 
                        backgroundColor: getStatusColor(stock.change),
                        padding: 'var(--ggui-spacing-xsmall, 4px) var(--ggui-spacing-small, 8px)',
                        borderRadius: 'var(--ggui-border-radius-small, 4px)',
                        color: 'var(--ggui-color-onPrimary, #ffffff)',
                        fontSize: 'var(--ggui-font-size-small, 12px)',
                        fontWeight: 'bold'
                      }}
                    >
                      {percent}
                    </div>
                  </Stack>
                </Stack>
              </Card>
            );
          })
        ) : (
          <Text variant="body-medium">Initial stocks loading...</Text>
        )}
      </div>

      {/* Footer */}
      <Stack direction="horizontal" justify="center" style={{ marginTop: 'var(--ggui-spacing-medium)' }}>
        <Text variant="body-small" style={{ opacity: 0.5 }}>
          Last Update Received: {lastUpdated}
        </Text>
      </Stack>
    </Stack>
  );
}

