import React, { useState } from 'react';
import { Card, Stack, Text, Button, Input } from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string; 
  };
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent({
  avatarOptions,
  roleOptions,
  initialProfile,
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(initialProfile?.name || '');
  const [email, setEmail] = useState(initialProfile?.email || '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '');
  const [role, setRole] = useState(initialProfile?.role || '');
  const [notifs, setNotifs] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme || 'light');

  const isValidEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const canNext1 = name.trim().length > 0 && isValidEmail(email);
  const canNext2 = role !== '';

  const progress = (step / 3) * 100;

  return (
    <Card variant="outline" style={{ maxWidth: '500px', width: '100%', margin: 'var(--ggui-space-lg) auto', padding: 'var(--ggui-space-md)' }}>
      <Stack gap="xl">
        <Stack gap="xs">
          <Stack direction="row" justify="space-between">
            <Text variant="label-sm">Step {step}/3</Text>
            <Text variant="label-sm">{Math.round(progress)}%</Text>
          </Stack>
          <div style={{ height: '4px', background: 'var(--ggui-color-surfaceVariant)', borderRadius: '9px' }}>
            <div style={{ height: '100%', width: progress + '%', background: 'var(--ggui-color-primary)', transition: 'width 0.3s', borderRadius: '9px' }} />
          </div>
        </Stack>

        {step === 1 && (
          <Stack gap="lg">
            <Text variant="title-md">Profile Setup</Text>
            <Stack gap="md">
              <Stack gap="xs">
                <Text as="label" htmlFor="user-name" variant="label-sm">Name</Text>
                <Input label="Name" id="user-name" value={name} onChange={(v: string) => setName(v)} />
              </Stack>
              <Stack gap="xs">
                <Text as="label" htmlFor="user-email" variant="label-sm">Email</Text>
                <Input label="Email" id="user-email" type="email" value={email} onChange={(v: string) => setEmail(v)} />
              </Stack>
              <Stack gap="sm">
                <Text variant="label-sm">Select Avatar</Text>
                <Stack direction="row" gap="sm">
                  {avatarOptions.map((o) => (
                    <Button key={o} variant={avatar === o ? 'primary' : 'outline'} onClick={() => setAvatar(o)} style={{ fontSize: '1.5rem', width: '3.5rem', height: '3.5rem', borderRadius: '50%' }}>{o}</Button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap="lg">
            <Text variant="title-md">Preferences</Text>
            <Stack gap="md">
              <Stack gap="sm">
                <Text variant="label-sm">Role</Text>
                <Stack direction="row" gap="sm" style={{ flexWrap: 'wrap' }}>
                  {roleOptions.map((o) => (
                    <Button key={o} variant={role === o ? 'secondary' : 'outline'} onClick={() => setRole(o)}>{o}</Button>
                  ))}
                </Stack>
              </Stack>
              <Stack direction="row" justify="space-between" align="center" style={{ background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-space-sm)', borderRadius: 'var(--ggui-radius-sm)' }}>
                <Text variant="body-md">Notifications</Text>
                <Button variant={notifs ? 'primary' : 'outline'} size="sm" onClick={() => setNotifs(!notifs)}>{notifs ? 'On' : 'Off'}</Button>
              </Stack>
              <Stack direction="row" justify="space-between" align="center" style={{ background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-space-sm)', borderRadius: 'var(--ggui-radius-sm)' }}>
                <Text variant="body-md">Theme</Text>
                <Button variant="outline" size="sm" onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')}>{theme === 'light' ? 'Light' : 'Dark'}</Button>
              </Stack>
            </Stack>
          </Stack>
        )}

        {step === 3 && (
          <Stack gap="lg">
            <Text variant="title-md">Review</Text>
            <Card variant="outline" style={{ background: 'var(--ggui-color-surfaceVariant)', border: 'none' }}>
              <Stack gap="md" padding="md">
                <Stack direction="row" gap="md" align="center">
                  <div style={{ fontSize: '3rem', background: 'var(--ggui-color-surface)', width: '4rem', height: '4rem', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{avatar}</div>
                  <Stack gap="none"><Text variant="title-sm">{name}</Text><Text variant="body-sm">{email}</Text></Stack>
                </Stack>
                <Stack gap="xs">
                  <Text variant="body-sm">Role: {role}</Text>
                  <Text variant="body-sm">Notifications: {notifs ? 'On' : 'Off'}</Text>
                  <Text variant="body-sm">Theme: {theme}</Text>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="row" justify="space-between">
          <Button variant="ghost" disabled={step === 1} onClick={() => setStep(step - 1)}>Back</Button>
          {step < 3 ? (
            <Button variant="primary" disabled={step === 1 ? !canNext1 : !canNext2} onClick={() => setStep(step + 1)}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onComplete?.({ name, email, avatar, role, emailNotifications: notifs, theme })}>Finish</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
