  humidity: number;
  /** Wind speed in standard units */
  windSpeed: number;
  /** Temperature unit symbol (e.g., °C, °F) */
  unit?: string;
  /** 5-day forecast data array */
  forecast: Array<ForecastItem>;
}

/**
 * WeatherCard Component
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 10,
  unit = '°',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 18 },
    { day: 'Tue', icon: '⛅', high: 22, low: 17 },
    { day: 'Wed', icon: '☁️', high: 19, low: 15 },
    { day: 'Thu', icon: '🌧️', high: 17, low: 14 },
    { day: 'Fri', icon: '🌤️', high: 21, low: 16 },
  ],
}: Props) {

  // Helper to map condition strings to emojis
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('partly')) return '⛅';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '🌡️';
  };

  const currentIcon = getConditionEmoji(condition);

  return (
    <Card 
      variant="elevated" 
      padding="xl"
      style={{ 
        maxWidth: '100%',
        width: '420px',
        backgroundColor: 'var(--ggui-color-surface)',
        color: 'var(--ggui-color-onSurface)',
        border: '1px solid var(--ggui-color-outlineVariant)',
        borderRadius: 'var(--ggui-radius-xl)',
        boxShadow: 'var(--ggui-shadow-md)',
      }}
    >
      <Stack gap="xl">
        {/* Header: City and Date */}
        <Stack direction="row" align="center" justify="space-between">
          <Stack gap="xs">
            <Text variant="h3" weight="bold" style={{ color: 'var(--ggui-color-primary)' }}>
              {city}
            </Text>
            <Text variant="body-sm" style={{ opacity: 0.7 }}>
              Today
            </Text>
          </Stack>
          <Text style={{ fontSize: '3.5rem', lineHeight: 1 }}>
            {currentIcon}
          </Text>
        </Stack>

        {/* Main Stats: Big Temperature */}
        <Stack align="center" gap="xs">
          <Stack direction="row" align="start">
             <Text 
              style={{ 
                fontSize: '5rem', 
                fontWeight: 'var(--ggui-font-weight-black)',
                lineHeight: 0.9,
                letterSpacing: '-2px'
              }}
            >
              {temperature}
            </Text>
            <Text variant="h2" weight="medium" style={{ marginTop: '0.5rem' }}>
              {unit}
            </Text>
          </Stack>
          <Text variant="h4" weight="medium" style={{ opacity: 0.9 }}>
            {condition}
          </Text>
        </Stack>

        {/* Atmospheric Details */}
        <Stack 
          direction="row" 
          justify="space-between" 
          style={{ 
            padding: 'var(--ggui-spacing-md)',
            backgroundColor: 'var(--ggui-color-surfaceContainer)',
            borderRadius: 'var(--ggui-radius-lg)',
          }}
        >
          <Stack align="center" gap="xs" style={{ flex: 1 }}>
            <Text variant="caption" weight="bold" style={{ opacity: 0.6, letterSpacing: '0.05em' }}>
              HUMIDITY
            </Text>
            <Text variant="body-md" weight="bold">{humidity}%</Text>
          </Stack>

          <div style={{ width: '1px', backgroundColor: 'var(--ggui-color-outlineVariant)', alignSelf: 'stretch' }} />

          <Stack align="center" gap="xs" style={{ flex: 1 }}>
            <Text variant="caption" weight="bold" style={{ opacity: 0.6, letterSpacing: '0.05em' }}>
              WIND SPEED
            </Text>
            <Text variant="body-md" weight="bold">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Stack direction="row" justify="space-between" align="center" style={{ width: '100%', paddingTop: 'var(--ggui-spacing-sm)' }}>
          {forecast.map((item, index) => (
            <Stack key={item.day || index} align="center" gap="sm" style={{ flex: 1 }}>
              <Text variant="caption" weight="bold" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                {item.day}
              </Text>
              <Text style={{ fontSize: '1.5rem' }}>
                {item.icon}
              </Text>
              <Stack gap="xs" align="center">
                <Text variant="body-xs" weight="bold">{item.high}{unit}</Text>
                <Text variant="body-xs" style={{ opacity: 0.5 }}>{item.low}{unit}</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Divider
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'alkaline-earth': 'var(--ggui-color-primary-400, #38bdf8)',
  'transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'post-transition-metal': 'var(--ggui-color-success-200, #bbf7d0)',
  'metalloid': 'var(--ggui-color-warning-200, #fef08a)',
  'nonmetal': 'var(--ggui-color-error-100, #fee2e2)',
  'halogen': 'var(--ggui-color-error-200, #fecaca)',
  'noble-gas': 'var(--ggui-color-info-200, #bae6fd)',
  'lanthanide': 'var(--ggui-color-primary-100, #e0f2fe)',
  'actinide': 'var(--ggui-color-primary-50, #f0f9ff)',
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return elements.map(el => ({
      ...el,
      isMatch: !term ||
        (el.name || '').toLowerCase().indexOf(term) !== -1 ||
        (el.symbol || '').toLowerCase().indexOf(term) !== -1
    }));
  }, [elements, searchTerm]);

  const uniqueCategories = useMemo(() => {
    const cats = Array.from(new Set(elements.map(e => e.category).filter(Boolean))) as string[];
    return cats.sort();
  }, [elements]);

  const formatCategory = (cat?: string) => {
    if (!cat) return '';
    return cat.split('-').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack align="center" gap={12}>
          <Text variant="h1" weight="bold">Periodic Table</Text>
          <Stack gap={4}>
            <Text as="label" htmlFor="q">Search</Text>
            <Input label="Search" id="q" value={searchTerm} onChange={setSearchTerm} placeholder="Filter..." />
          </Stack>
        </Stack>

        <Card padding={12}>
          <Row wrap gap={16} justify="center">
            {uniqueCategories.map(cat => (
              <Row key={cat} gap={8} align="center">
                <Box
                  style={{
                    width: 16,
                    height: 16,
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    backgroundColor: CATEGORY_COLORS[cat] || 'var(--ggui-color-neutral-100)'
                  }}
                />
                <Text variant="caption" weight="medium">{formatCategory(cat)}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4)',
            minWidth: '800px'
          }}
        >
          {filteredElements.map((el) => {
            const elKey = (el.atomicNumber ? String(el.atomicNumber) : '') + '-' + (el.symbol || '');
            const elColor = CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-surfaceVariant)';
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <Box
                key={elKey}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  cursor: 'pointer',
                  opacity: el.isMatch ? 1 : 0.2,
                  transition: 'all 200ms ease-in-out',
                  transform: isSelected ? 'scale(1.1)' : 'none',
                  zIndex: isSelected ? 10 : 1,
                }}
              >
                <Card
                  padding={4}
                  style={{
                    height: '100%',
                    aspectRatio: '1/1',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    position: 'relative',
                    backgroundColor: elColor,
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600)'
                      : '1px solid var(--ggui-color-outlineVariant)',
                  }}
                >
                  <Box style={{ position: 'absolute', top: 2, left: 4 }}>
                    <Text variant="caption" style={{ fontSize: '10px' }}>{el.atomicNumber}</Text>
                  </Box>
                  <Text weight="bold" style={{ fontSize: '1.1rem' }}>{el.symbol}</Text>
                  <Text variant="caption" style={{ fontSize: '8px', opacity: 0.8, textAlign: 'center' }}>{el.name}</Text>
                </Card>
              </Box>
            );
          })}
        </Box>

        <Box style={{ minHeight: '180px' }}>
          {selectedElement ? (
            <Card
              padding={24}
              style={{
                borderLeft: '8px solid ' + (CATEGORY_COLORS[selectedElement.category || ''] || 'var(--ggui-color-neutral-300)'),
              }}
            >
              <Stack gap={16}>
                <Row justify="between" align="start">
                  <Stack gap={4}>
                    <Text variant="h2" weight="bold">{selectedElement.name}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{formatCategory(selectedElement.category)}</Text>
                  </Stack>
                  <Stack align="end">
                    <Text weight="bold" style={{ fontSize: '2.5rem', lineHeight: 1 }}>{selectedElement.symbol}</Text>
                    <Text variant="label">Atomic No. {selectedElement.atomicNumber}</Text>
                  </Stack>
                </Row>
                <Divider />
                <Row wrap gap={32}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text weight="semibold">{selectedElement.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Electron Config</Text>
                    <Text weight="semibold">{selectedElement.electronConfiguration}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                    <Text weight="semibold">R{selectedElement.row} C{selectedElement.col}</Text>
                  </Stack>
                </Row>
              </Stack>
            </Card>
          ) : (
            <Box style={{ textAlign: 'center', padding: '48px', border: '2px dashed var(--ggui-color-outline)', borderRadius: '12px' }}>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            </Box>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

