/**
 * StockTickerDashboard component displays live stock prices in a grid.
 * It listens for 'ggui:agent-data' events for real-time price updates.
 */
export default function StockTickerDashboard({
  stocks = [
    { symbol: 'AAPL', name: 'Apple Inc.', price: 175.24, change: 1.45, changePercent: 0.83 },
    { symbol: 'MSFT', name: 'Microsoft Corp.', price: 415.52, change: -2.10, changePercent: -0.50 },
    { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 152.12, change: 0.88, changePercent: 0.58 },
    { symbol: 'TSLA', name: 'Tesla, Inc.', price: 171.05, change: -4.32, changePercent: -2.46 }
  ]
}: Props) {
  const [stocksData, setStocksData] = useState<Stock[]>(stocks);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [isConnected] = useState(true);
  const { motionEnabled } = useMotion();

  // Update local state when props change
  useEffect(() => {
    setStocksData(stocks);
  }, [stocks]);

  // Listen for real-time price updates via the stream contract
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { type, data } = customEvent.detail || {};

      if (type === 'price-update' && data?.symbol) {
        setStocksData((prevStocks) =>
          prevStocks.map((stock) =>
            stock.symbol === data.symbol
              ? {
                  ...stock,
                  price: data.price ?? stock.price,
                  change: data.change ?? stock.change,
                  changePercent: data.changePercent ?? stock.changePercent,
                }
              : stock
          )
        );
        setLastUpdated(new Date().toLocaleTimeString());
      }
    };

    addEventListener('ggui:agent-data', handleAgentData);
    return () => removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Formatter for currency
  const formatCurrency = (value?: number) => {
    if (value === undefined) return '--';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(value);
  };

  // Formatter for change values
  const formatChange = (value?: number) => {
    if (value === undefined) return '--';
    const sign = value >= 0 ? '+' : '';
    return sign + value.toFixed(2);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Row justify="between" align="center" wrap="wrap" gap={16}>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Row gap={8} align="center">
              <div
                aria-hidden="true"
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: '50%',
                  backgroundColor: isConnected ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-onSurfaceVariant)',
                  boxShadow: isConnected ? '0 0 8px var(--ggui-color-success-600)' : 'none',
                }}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {isConnected ? 'Live Connection Active' : 'Connecting...'}
              </Text>
            </Row>
          </Stack>
          <Stack align="end" gap={0}>
            <Text variant="label" weight="semibold">Current Time</Text>
            <Text variant="h3">{new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</Text>
          </Stack>
        </Row>

        <Divider margin={0} />

        {/* Grid of Stock Cards */}
        <div
          role="region"
          aria-label="Stock prices"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
            animation: motionEnabled ? animation.fadeIn : 'none',
          }}
        >
          {stocksData.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            const variant = isPositive ? 'success' : 'error';

            return (
              <Card
                key={stock.symbol || index}
                padding="var(--ggui-spacing-4)"
                style={{
                  transition: transition.all,
                  borderLeft: '4px solid ' + statusColor,
                  backgroundColor: 'var(--ggui-color-surface)',
                  position: 'relative',
                  overflow: 'hidden'
                }}
              >
                <Stack gap={16}>
                  <Row justify="between" align="start">
                    <Stack gap={0}>
                      <Text variant="h3" weight="bold" style={{ letterSpacing: 'var(--ggui-letter-spacing-tight)' }}>
                        {stock.symbol}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name}
                      </Text>
                    </Stack>
                    <Badge variant={variant} size="md">
                      {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                    </Badge>
                  </Row>

                  <Stack gap={4}>
                    <Text variant="h2" weight="bold">
                      {formatCurrency(stock.price)}
                    </Text>
                    <Row gap={4} align="center">
                      <Text
                        variant="bodySmall"
                        weight="bold"
                        style={{ color: statusColor }}
                      >
                        {formatChange(stock.change)}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        Today
                      </Text>
                    </Row>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>

        {/* Footer info */}
        <Row justify="center" style={{ marginTop: 'var(--ggui-spacing-4)' }}>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Last updated: {lastUpdated} • Data provided by Agent
          </Text>
        </Row>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Button, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Callback when user completes onboarding */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const {
    avatarOptions = ['👤', '🚀', '🎨', '💻'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    initialProfile = {},
    onComplete
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || avatarOptions[0] || '👤',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isValid = useMemo(() => {
    if (step === 1) return formData.name.trim().length > 0 && isEmailValid(formData.email);
    if (step === 2) return formData.role !== '';
    return true;
  }, [step, formData]);

  const update = (field: string, value: any) => setFormData(f => ({ ...f, [field]: value }));

  const progress = step === 1 ? '33%' : step === 2 ? '66%' : '100%';

  return (
    <Card variant="elevated" style={{ maxWidth: '480px', margin: 'var(--ggui-spacing-large) auto' }}>
      <Stack gap="large" padding="xlarge">
        <Stack gap="small">
          <Stack direction="row" justify="space-between" align="center">
            <Text variant="label" weight="bold">Step {String(step)} of 3</Text>
            <Text variant="caption" color="subtle">{step === 1 ? 'Setup' : step === 2 ? 'Preferences' : 'Review'}</Text>
          </Stack>
          <div style={{ height: 'var(--ggui-spacing-xsmall)', width: '100%', background: 'var(--ggui-color-outline)', borderRadius: 'var(--ggui-border-radius-pill)' }}>
            <div style={{ height: '100%', width: progress, background: 'var(--ggui-color-primary)', transition: 'width 0.3s' }} />
          </div>
        </Stack>

        <div style={{ minHeight: '300px' }}>
          {step === 1 && (
            <Stack gap="medium">
              <Text variant="heading">Profile Setup</Text>
              <Input label="Full Name" placeholder="Enter name" value={formData.name} onChange={(v: string) => update('name', v)} />
              <Input label="Email Address" type="email" placeholder="email@example.com" value={formData.email} onChange={(v: string) => update('email', v)} />
              <Stack gap="small">
                <Text variant="label">Avatar</Text>
                <Stack direction="row" gap="small" wrap="wrap">
                  {avatarOptions.map(a => (
                    <Button key={a} variant={formData.avatar === a ? 'primary' : 'outline'} onClick={() => update('avatar', a)} style={{ width: '48px', height: '48px', padding: 0 }}>{a}</Button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="medium">
              <Text variant="heading">Preferences</Text>
              <Stack gap="small">
                <Text variant="label">Role</Text>
                <Stack direction="row" gap="small" wrap="wrap">
                  {roleOptions.map(r => (
                    <Button key={r} variant={formData.role === r ? 'primary' : 'outline'} onClick={() => update('role', r)} size="small">{r}</Button>
                  ))}
                </Stack>
              </Stack>
              <Stack direction="row" justify="space-between" align="center">
                <Text variant="body">Email Notifications</Text>
                <Button variant={formData.emailNotifications ? 'primary' : 'outline'} onClick={() => update('emailNotifications', !formData.emailNotifications)} size="small">
                  {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                </Button>
              </Stack>
              <Stack direction="row" justify="space-between" align="center">
                <Text variant="body">Theme Preference</Text>
                <Stack direction="row" gap="none" style={{ border: '1px solid var(--ggui-color-outline)', borderRadius: 'var(--ggui-border-radius-medium)', overflow: 'hidden' }}>
                  <Button variant={formData.theme === 'light' ? 'primary' : 'ghost'} size="small" onClick={() => update('theme', 'light')}>Light</Button>
                  <Button variant={formData.theme === 'dark' ? 'primary' : 'ghost'} size="small" onClick={() => update('theme', 'dark')}>Dark</Button>
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="medium">
              <Text variant="heading">Final Review</Text>
              <Card variant="outline" padding="medium">
                <Stack gap="small">
                  <Text variant="body"><strong>Name:</strong> {formData.name}</Text>
                  <Text variant="body"><strong>Email:</strong> {formData.email}</Text>
                  <Text variant="body"><strong>Avatar:</strong> {formData.avatar}</Text>
                  <Text variant="body"><strong>Role:</strong> {formData.role}</Text>
                  <Text variant="body"><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </div>

        <Stack direction="row" justify="space-between">
          <Button variant="ghost" onClick={() => setStep(step - 1)} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={() => setStep(step + 1)} disabled={!isValid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => onComplete?.(formData)}>Complete Setup</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionIcon = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun')) return '☀️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain')) return '🌧️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
  return '☁️';
};

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const tempText = String(temperature) + '°' + (unit || 'C');
  const humidityText = String(humidity) + '%';
  const windUnit = unit === 'F' ? 'mph' : 'km/h';
  const windText = String(windSpeed) + ' ' + windUnit;
  const conditionIcon = getConditionIcon(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      role="region"
      aria-label={'Weather for ' + city}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Stack direction="horizontal" justify="between" align="start">
          <Text
            variant="h3"
            weight="semibold"
            style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
          >
            {city}
          </Text>
          <Box
            aria-hidden="true"
            style={{
              background: 'var(--ggui-color-container, #ede9fe)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: '44px',
              textAlign: 'center',
            }}
          >
            <Text variant="h3" style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}>
              {conditionIcon}
            </Text>
          </Box>
        </Stack>

        <Stack direction="vertical" gap={4}>
          <Text
            variant="h1"
            weight="bold"
            style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
          >
            {tempText}
          </Text>
          <Text
            variant="body"
            weight="medium"
            style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
          >
            {condition}
          </Text>
        </Stack>

        <Stack direction="horizontal" justify="between" align="center" wrap={true}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
            >
              {humidityText}
            </Text>
          </Stack>

          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
            >
              Wind
            </Text>
            <Text
              variant="body"
              weight="semibold"
              style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
            >
              {windText}
            </Text>
          </Stack>
        </Stack>

        <Divider style={{ borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)' }} />

        <Stack
          direction="horizontal"
          justify="between"
          align="stretch"
          wrap={true}
          aria-label="5-day forecast"
        >
          {forecast.slice(0, 5).map((item, index) => {
            const day = item.day ?? '—';
            const icon = item.icon ?? '☁️';
            const highText =
              item.high != null ? 'H:' + String(item.high) + '°' + (unit || 'C') : 'H:—';
            const lowText =
              item.low != null ? 'L:' + String(item.low) + '°' + (unit || 'C') : 'L:—';

            return (
              <Box
                key={item.day ?? index}
                aria-label={day + ': high ' + highText + ', low ' + lowText}
                style={{
                  background: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  flex: 1,
                  minWidth: '72px',
                  transition: 'background-color 150ms ease',
                }}
              >
                <Stack direction="vertical" gap={4} align="center">
                  <Text
                    variant="caption"
                    weight="medium"
                    style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                  >
                    {day}
                  </Text>
                  <Text variant="body" aria-hidden="true">
                    {icon}
                  </Text>
                  <Stack direction="horizontal" gap={4}>
                    <Text variant="caption" style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>
                      {highText}
                    </Text>
                    <Text
                      variant="caption"
                      style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                    >
                      {lowText}
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Card>
  );
}
